  1	import React, { FC, useState } from 'react';
  2	
  3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  4	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
