 10	  ActionList,
 11	  ActionListItem,
 12	  Button,
 13	  ButtonVariant,
 14	  DescriptionList,
 15	  DescriptionListDescription,
 16	  DescriptionListGroup,
 17	  DescriptionListTerm,
 18	} from '@patternfly/react-core';
 19	import { CloseIcon } from '@patternfly/react-icons';
 20	
 21	import useCurrentStorageMigration from './hooks/useCurrentStorageMigration';
 22	import { getMigrationStatusLabel, getMigrationSuccessTimestamp } from './utils';
 23	import VirtualMachineMigrationRollback from './VirtualMachineMigrationRollback';
 24	
 25	type VirtualMachineMigrationStatusProps = {
 26	  onClose: () => void;
 27	  vm: V1VirtualMachine;
 28	};
 29	
 30	const VirtualMachineMigrationStatus: FC<VirtualMachineMigrationStatusProps> = ({ onClose, vm }) => {
 31	  const { t } = useKubevirtTranslation();
 32	  const vmim = useCurrentStorageMigration(vm);
 33	  const [rollbacking, setRollbacking] = useState(false);
 34	
 35	  const migrationPod = getMigrationPod(vmim);
 36	  const migrationLogURL = migrationPod && `/k8s/ns/default/pods/${migrationPod}/logs`;
 37	
 38	  const migrationCompleted = vmimStatuses.Succeeded === vmim?.status?.phase;
 39	
 40	  if (rollbacking)
 41	    return (
 42	      <VirtualMachineMigrationRollback
 43	        onClose={onClose}
 44	        onContinue={() => setRollbacking(false)}
 45	        vm={vm}
 46	      />
 47	    );
 48	
 49	  return (
 50	    <div className="pf-v6-c-wizard migration-status">
 51	      <div className="pf-v6-c-wizard__header">
 52	        <div className="pf-v6-c-wizard__close">
 53	          <Button aria-label={t('Close')} onClick={onClose} variant={ButtonVariant.plain}>
 54	            <CloseIcon />
 55	          </Button>
 56	        </div>
 57	        <div className="pf-v6-c-wizard__title">
 58	          <h2 className="pf-v6-c-wizard__title-text">{t('Migrate VirtualMachine storage')}</h2>
 59	        </div>
 60	        <div className="pf-v6-c-wizard__description">
 61	          {t('Migrate VirtualMachine storage to a different StorageClass.')}
 62	        </div>
 63	      </div>
 64	
 65	      <DescriptionList className="migration-status__body">
 66	        <DescriptionListGroup>
 67	          <DescriptionListTerm>{getMigrationStatusLabel(vmim)}</DescriptionListTerm>
 68	        </DescriptionListGroup>
 69	
 70	        <DescriptionListGroup>
 71	          <DescriptionListTerm>{t('Started on')}</DescriptionListTerm>
 72	          <DescriptionListDescription>
 73	            {vmim?.metadata?.creationTimestamp ? (
 74	              <Timestamp timestamp={vmim?.metadata?.creationTimestamp} />
 75	            ) : (
 76	              t('Not started yet')
 77	            )}
 78	          </DescriptionListDescription>
 79	        </DescriptionListGroup>
 80	
 81	        <DescriptionListGroup>
 82	          <DescriptionListTerm>{t('Status')}</DescriptionListTerm>
 83	          <DescriptionListDescription>
 84	            {vmim?.status?.phase || t('Requested')}
 85	
 86	            {migrationCompleted && (
 87	              <>
 88	                {t('Migrated at')} <Timestamp timestamp={getMigrationSuccessTimestamp(vmim)} />{' '}
 89	              </>
 90	            )}
 91	          </DescriptionListDescription>
 92	        </DescriptionListGroup>
 93	      </DescriptionList>
 94	
 95	      <ActionList>
 96	        <ActionListItem>
 97	          {!migrationCompleted && (
 98	            <Button onClick={() => setRollbacking(true)} variant={ButtonVariant.secondary}>
 99	              {t('Stop')}
100	            </Button>
101	          )}
102	        </ActionListItem>
103	        {migrationLogURL && (
104	          <ActionListItem className="migration-status__view-report">
105	            <ExternalLink href={migrationLogURL}>{t('View report')}</ExternalLink>
106	          </ActionListItem>
107	        )}
108	      </ActionList>
109	    </div>
110	  );
111	};
112	
113	export default VirtualMachineMigrationStatus;

